mapper.select:
    /*AcenRcpMgmtMapper.selectAcenRcpMgmtListExcel*/

      SELECT DISTINCT
          ACEN.REQUEST_KEY
        , TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY  /*신청일자*/
        , REQ.RES_NO  /*예약번호*/
        , CST.CSTMR_NAME AS CSTMR_NM  /*고객명*/
        , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN))), '-', ''), 0, 6) AS BIRTH_DT  /*생년월일*/
        , DECODE(TRIM(CST.CSTMR_MOBILE_FN) || TRIM(CST.CSTMR_MOBILE_MN) || TRIM(CST.CSTMR_MOBILE_RN), '',
                 TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN),
                 TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN)) AS CSTMR_MOBILE  /*휴대폰번호*/
        , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST
           WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID AND ROWNUM = 1) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NM  /*대리점*/
        , FN_GET_CODENM('RCP0007', NVL(REQ.ON_OFF_TYPE, 0)) AS ON_OFF_NM  /*모집경로*/
        , (SELECT RATE_NM FROM MSP_RATE_MST
           WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1)
           || '(' || SAL.SOC_CODE || ')' AS SOC_NM	 /*요금제*/
        , FN_GET_CODENM('RCP9001', REQ.OPER_TYPE) AS OPER_NM  /*업무구분*/
        , FN_GET_CODENM('RCP0006', REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NM  /*진행상태*/
        , FN_GET_CODENM('RCP0005', REQ.PSTATE) AS PSTATE_NM  /*신청서상태*/
        , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인'
               ELSE (SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1)
                     FROM   MSP_PARTNER_USIM_MST PUM
                     WHERE  REQ.REQ_USIM_SN = PUM.USIM_NO)
               END AS USIM_ORG_NM  /*유심접점*/
        , FN_GET_CODENM('RCP9032', DLV.DLVRY_TYPE) AS DLVRY_TYPE_NM  /*배송방법*/
        , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
           WHERE CD_GROUP_ID = 'AcenEvntGrp'
           AND DTL_CD = ACEN.EVNT_GRP_CD) AS ACEN_EVNT_GRP_NM  /*시나리오*/
        , CASE ACEN.SUCC_YN WHEN 'Y' THEN '성공'
                            WHEN 'N' THEN '실패'
                            ELSE '진행중' END AS ACEN_STATUS  /*성공여부*/
        , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
           WHERE CD_GROUP_ID = 'AcenEvntType'
           AND DTL_CD = ACEN.EVNT_TYPE) AS ACEN_EVNT_TYPE_NM  /*시나리오(상세)*/
        , DECODE(ACEN.REQ_STATUS, 'Y', '요청','미요청') AS REQ_STATUS_NM  /*요청여부*/
        , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
           WHERE CD_GROUP_ID = 'AcenErrCd'
           AND DTL_CD = ACEN.RMK) AS ACEN_FAIL_RMK  /*실패사유*/
        , REQ.MEMO AS REQUEST_MEMO  /*처리메모*/
        , DECODE(REQ.RVISN_ID, 'ACEN', REQ.RVISN_ID, FN_GET_USRNM(REQ.RVISN_ID)) AS RVISN_NM  /*수정자*/
        , TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM  /*수정일시*/
        , DECODE(ACEN.RTY_ID, NULL, 'N', 'Y') AS RTY_YN
        , DECODE(REQ.USIM_KINDS_CD , '09' , 'Y' , 'N') AS USIM_KINDS_CD /*eSIM여부*/
      FROM NMCP_ACEN_REQ@DL_MCP ACEN
         , MCP_REQUEST@DL_MCP REQ
         , MCP_REQUEST_CSTMR@DL_MCP CST
         , MCP_REQUEST_SALEINFO@DL_MCP SAL
         , MCP_REQUEST_DLVRY@DL_MCP DLV
         , NMCP_USIM_BUY_TXN@DL_MCP MSD
      WHERE ACEN.REQUEST_KEY = REQ.REQUEST_KEY
      AND ACEN.REQUEST_KEY = CST.REQUEST_KEY
      AND ACEN.REQUEST_KEY = SAL.REQUEST_KEY
      AND ACEN.REQUEST_KEY = DLV.REQUEST_KEY
      AND REQ.REQ_USIM_SN = MSD.REQ_USIM_SN(+)
      /*신청일자필터*/

        AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{srchStrtDt},'YYYYMMDD') AND TO_DATE(#{srchEndDt},'YYYYMMDD') + 1

      /*업무구분필터*/

        AND REQ.OPER_TYPE = #{pOperType}

      /*구매유형필터*/

        AND REQ.REQ_BUY_TYPE = #{pReqBuyType}

      /*대리점필터*/

        AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})

      /*진행상태필터*/

        AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode}

      /*신청취소필터*/

        AND REQ.PSTATE = #{pPstate}

      /*시나리오필터*/

        AND ACEN.EVNT_GRP_CD = #{pAcenEvntGrp}

      /*성공여부필터*/

        AND ACEN.SUCC_YN = #{pSuccYn}

      /*실패사유필터*/

        AND ACEN.RMK = #{pAcenErrCd}

      /*모집경로필터*/

        AND REQ.ON_OFF_TYPE = #{pOnOffType}

      /*eSIM여부필터*/

        AND REQ.USIM_KINDS_CD = '09'

      /*검색구분필터-고객명*/

        AND CST.CSTMR_NAME LIKE #{pSearchName} || '%'

      /*검색구분필터-계약번호*/

        AND REQ.CONTRACT_NUM = #{pSearchName}

      /*검색구분필터-연락처*/

        AND (CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890')
             OR CST.CSTMR_TEL_FN || CST.CSTMR_TEL_MN || CST.CSTMR_TEL_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890'))

      /*검색구분필터-단말기일련번호*/

        AND REQ.REQ_PHONE_SN = #{pSearchName}

      /*검색구분필터-예약번호*/

        AND REQ.RES_NO = #{pSearchName}

      /*검색구분필터-요금제*/

        AND SAL.SOC_CODE IN (SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%')

      /*셀프개통 제외 필터*/

	    AND REQ.ON_OFF_TYPE NOT IN ('5','7')

      ORDER BY ACEN.REQUEST_KEY DESC

   /*AcenRcpMgmtMapper.selectAcenRcpMgmtFailListExcel*/

     SELECT DISTINCT
         ACEN.REQUEST_KEY
       , ACEN.SEQ
       , TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY  /*신청일자*/
       , REQ.RES_NO  /*예약번호*/
       , CST.CSTMR_NAME AS CSTMR_NM  /*고객명*/
       , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN))), '-', ''), 0, 6) AS BIRTH_DT  /*생년월일*/
       , DECODE(TRIM(CST.CSTMR_MOBILE_FN) || TRIM(CST.CSTMR_MOBILE_MN) || TRIM(CST.CSTMR_MOBILE_RN), '',
                TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN),
                TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN)) AS CSTMR_MOBILE  /*휴대폰번호*/
       , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST
          WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID AND ROWNUM = 1) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NM  /*대리점*/
       , FN_GET_CODENM('RCP0007', NVL(REQ.ON_OFF_TYPE, 0)) AS ON_OFF_NM  /*모집경로*/
       , (SELECT RATE_NM FROM MSP_RATE_MST
          WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1)
          || '(' || SAL.SOC_CODE || ')' AS SOC_NM	 /*요금제*/
       , FN_GET_CODENM('RCP9001', REQ.OPER_TYPE) AS OPER_NM  /*업무구분*/
       , FN_GET_CODENM('RCP0006', REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NM  /*진행상태*/
       , FN_GET_CODENM('RCP0005', REQ.PSTATE) AS PSTATE_NM  /*신청서상태*/
       , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인'
         ELSE (SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1)
               FROM   MSP_PARTNER_USIM_MST PUM
               WHERE  REQ.REQ_USIM_SN = PUM.USIM_NO)
               END AS USIM_ORG_NM  /*유심접점*/
       , FN_GET_CODENM('RCP9032', DLV.DLVRY_TYPE) AS DLVRY_TYPE_NM  /*배송방법*/
       , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
          WHERE CD_GROUP_ID = 'AcenEvntGrp'
          AND DTL_CD = ACEN.EVNT_GRP_CD) AS ACEN_EVNT_GRP_NM  /*시나리오*/
       , '실패' AS ACEN_STATUS  /*성공여부*/
       , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
          WHERE CD_GROUP_ID = 'AcenEvntType'
          AND DTL_CD = ACEN.EVNT_TYPE) AS ACEN_EVNT_TYPE_NM  /*시나리오(상세)*/
       , DECODE(ACEN.REQ_STATUS, 'Y', '요청','미요청') AS REQ_STATUS_NM  /*요청여부*/
       , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
          WHERE CD_GROUP_ID = 'AcenErrCd'
          AND DTL_CD = ACEN.FAIL_RMK) AS ACEN_FAIL_RMK  /*실패사유*/
       , TO_CHAR(ACEN.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS ACEN_FAIL_DTTM  /*실패일시*/
       , REQ.MEMO AS REQUEST_MEMO  /*처리메모*/
       , DECODE(REQ.RVISN_ID, 'ACEN', REQ.RVISN_ID, FN_GET_USRNM(REQ.RVISN_ID)) AS RVISN_NM  /*수정자*/
       , TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM  /*수정일시*/
       , DECODE(ACEN.RTY_ID, NULL, 'N', 'Y') AS RTY_YN
       , DECODE(REQ.USIM_KINDS_CD , '09' , 'Y' , 'N') AS USIM_KINDS_CD /*eSIM여부*/
     FROM
         NMCP_ACEN_FAIL_HIST@DL_MCP ACEN
       , MCP_REQUEST@DL_MCP REQ
       , MCP_REQUEST_CSTMR@DL_MCP CST
       , MCP_REQUEST_SALEINFO@DL_MCP SAL
       , MCP_REQUEST_DLVRY@DL_MCP DLV
       , NMCP_USIM_BUY_TXN@DL_MCP MSD
     WHERE ACEN.REQUEST_KEY = REQ.REQUEST_KEY
     AND ACEN.REQUEST_KEY = CST.REQUEST_KEY
     AND ACEN.REQUEST_KEY = SAL.REQUEST_KEY
     AND ACEN.REQUEST_KEY = DLV.REQUEST_KEY
     AND REQ.REQ_USIM_SN = MSD.REQ_USIM_SN(+)
     /*신청일자필터*/

       AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{srchStrtDt},'YYYYMMDD') AND TO_DATE(#{srchEndDt},'YYYYMMDD') + 1

     /*업무구분필터*/

       AND REQ.OPER_TYPE = #{pOperType}

     /*구매유형필터*/

       AND REQ.REQ_BUY_TYPE = #{pReqBuyType}

     /*대리점필터*/

       AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})

     /*진행상태필터*/

       AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode}

     /*신청취소필터*/

       AND REQ.PSTATE = #{pPstate}

     /*시나리오필터*/

       AND ACEN.EVNT_GRP_CD = #{pAcenEvntGrp}

     /*실패사유필터*/

       AND ACEN.FAIL_RMK = #{pAcenErrCd}

     /*모집경로필터*/

       AND REQ.ON_OFF_TYPE = #{pOnOffType}

     /*eSIM여부필터*/

       AND REQ.USIM_KINDS_CD = '09'

     /*검색구분필터-고객명*/

       AND CST.CSTMR_NAME LIKE #{pSearchName} || '%'

     /*검색구분필터-계약번호*/

       AND REQ.CONTRACT_NUM = #{pSearchName}

     /*검색구분필터-연락처*/

       AND (CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890')
       OR CST.CSTMR_TEL_FN || CST.CSTMR_TEL_MN || CST.CSTMR_TEL_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890'))

     /*검색구분필터-단말기일련번호*/

       AND REQ.REQ_PHONE_SN = #{pSearchName}

     /*검색구분필터-예약번호*/

       AND REQ.RES_NO = #{pSearchName}

     /*검색구분필터-요금제*/

       AND SAL.SOC_CODE IN (SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%')

     /*셀프개통 제외 필터*/

	 	AND REQ.ON_OFF_TYPE NOT IN ('5','7')

     ORDER BY REQUEST_KEY DESC, SEQ
